UPDATE public.questions SET
  stimulus_text = 'The speaker notes that the trees had "all been born long ago."   This phrase suggests that the trees were alive before any of the three viewers were born.   What is the most likely reason why the writer chose the phrase "all been born long ago"? Subsequent paragraphs reinforce the same line of reasoning with additional examples, helping readers see how the author connects specific observations to a general claim without overstating certainty.',
