  stimulus_type = NULL,
  options = '[{"id":"A","text":"because. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"despite. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"however,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"therefore,. This choice completes the idea as a full sentence rather than a fragment.","is_correct":true,"explanation":"Choice D matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'D',
  explanation = 'The transition to a workplace that relies heavily on AI will require careful planning and management. Therefore, the use of AI will become more widespread in the coming years. The use of a semicolon and a conjunctive adverb creates the appropriate relationship between the two ideas in the sentence.  Because the second clause provides a logical consequence of the first clause, the use of the conjunctive adverb "therefore" is the most appropriate choice. The passage states that "The debate over the use of artificial intelligence in the workplace is complex. Many people are concerned about the pote…", which is the textual anchor for eliminating weaker choices. Choice D is correct because it aligns with that evidence: therefore,. This choice completes the idea as a full sentence rather than a fragment.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"FSS","domain_id":"conventions","opensat_index":1152,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_c4","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.904Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
  updated_at = now()
