UPDATE public.questions SET
  stimulus_text = 'A group of students are working on a project for their English class. They need to research and write a report on a famous author. They decide to write about Jane Austen.  One student writes the following sentence in their report: "Austen was a prolific writer, she published six novels in her lifetime." Researchers note that the pattern described above remained consistent across repeated observations, suggesting the finding was not a one-time anomaly. They caution that local conditions can still vary, yet the overall relationship held in each documented case.',
  question_text = 'Which choice correctly revises the sentence to conform to the conventions of Standard English?',
